	('prod_c22fdc41-fed4-44b0-b4b4-d5d40387bd7a', 'electric-jhoomer', 'Electric Jhoomer', '<ul><li><p>:- Electrical Musical Jhoomer Toy – A rotating merry-go-round with soothing music and cute dangling charms to engage and entertain babies.</p></li><li><p>🧸 100% Baby-Safe Materials – Made from non-toxic, BPA-free plastic with smooth, rounded edges to ensure safe playtime.</p></li><li><p>🔋 Battery Operated – Runs on 2 AA batteries (not included). Easy on/off switch with automatic gear mechanism – no winding needed.</p></li><li><p>🎵 Gentle Musical Melody – Plays a calming lullaby that soothes your baby and supports auditory development.</p></li><li><p>💖 Charming Dangling Elements – Colorful hanging toys move with the rotation, helping stimulate visual tracking and sensory awareness.</p></li></ul>', 249, 'https://cdn.toycker.in/products/0b68441b-b304-4fbb-901e-a603ffef0b88.jpeg', 20, '{"compare_at_price": 499}', '2025-12-28 10:59:10.096622+00', '2025-12-28 10:59:10.096622+00', 'cat_94b4dcf4-745a-4430-a23c-e10f79594fa6', 'col_2d93c2b4-019b-4a43-a2de-247608984c0f', 'active', 'https://cdn.toycker.in/uploads/electric-jhoomer/5a0ff065-8207-4a15-8d04-34b1b90c3548.jpg', '{https://cdn.toycker.in/products/0b68441b-b304-4fbb-901e-a603ffef0b88.jpeg,https://cdn.toycker.in/products/8b3824e5-71f1-470c-8946-c3e1b0cbe3ec.jpeg,https://cdn.toycker.in/products/0a8739ef-8e15-48de-abc6-15eb6711800f.jpeg}', 'inr', NULL, '', '', '[0.043730576,0.000803992,0.026074331,-0.018985817,0.0047070626,0.006250676,0.03225798,0.041451044,-0.00484063,0.013894155,-0.015723476,0.0042318767,-0.019909516,-0.037627626,0.047777552,-0.009779517,-0.076039694,-0.017264806,-0.0057716626,-0.04573544,-0.023481697,-0.008197527,0.023498528,0.09861742,0.0030971444,0.008534056,0.026544012,-0.0033512653,-0.000102376005,0.012880638,-0.0002102479,0.01491406,-0.04931457,0.021951526,-0.031132141,-0.02079836,-0.001372317,0.013100118,-0.0057471707,-0.036625154,-0.012079948,0.014534931,0.03516391,0.016812654,0.02178785,-0.041813,-