	('prod_17701383-c5e2-438f-8dcb-52d064f1e3cb', 'kiddie-floats-74-cm', 'kiddie floats 74 cm', '<ul><li><p>INFLATABLE WATER VEHICLE: Now you can race across the water with the Cars Water Vehicle, now in inflatable boat format for an adventurous day at the swimming pool, beach or lake!</p></li><li><p>ENCOURAGES IMAGINATIVE PLAY: Children will enter a world of their own imagination as they role play as Lightning McQueen on this pool float to race across the water with their favorite Cars character!</p></li><li><p>TAKE CONTROL: Dash panel features detailed control graphics to offer kids more opportunities to customize their experience and assume the role of the captain of their extraordinary floating boat</p></li></ul><p>&nbsp;</p>', 450, 'https://cdn.toycker.in/uploads/kiddie-floats-74-cm/4574f5e2-ab26-404c-984e-5b24f9475289.jpg', 20, '{"compare_at_price": 599.01}', '2025-12-28 10:59:13.192236+00', '2025-12-28 10:59:13.192236+00', 'cat_5ae74dd4-6a65-47ae-a155-00434fc18e2a', 'col_4d51f80f-e115-49f5-9990-8277b8b5a8b3', 'active', 'https://cdn.toycker.in/uploads/kiddie-floats-74-cm/c772adbc-5f27-4bc1-83d5-3a53f9e0007f.jpg', '{https://cdn.toycker.in/uploads/kiddie-floats-74-cm/4574f5e2-ab26-404c-984e-5b24f9475289.jpg,https://cdn.toycker.in/uploads/kiddie-floats-74-cm/5709c5d8-154c-4b95-b772-1b11fe690a71.jpg,https://cdn.toycker.in/uploads/kiddie-floats-74-cm/8bcbb31f-1feb-4863-aa44-b0549de0382d.jpg,https://cdn.toycker.in/uploads/kiddie-floats-74-cm/8615eaa5-fc24-4166-9a02-72bc913738b0.jpg}', 'inr', NULL, '', '', '[-0.009966245,0.0024030458,0.00012312208,0.03498236,0.040379897,-0.007075406,-0.0052334857,0.03499644,-0.0036833272,-0.0020407003,0.002456825,0.021218512,0.040585127,-0.017723264,-0.03111278,-0.01420509,0.08722482,0.03605563,-0.05037125,-0.012907369,-0.10100764,0.021051256,-0.020171462,0.036459606,0.007806731,0.009923209,-0.018799042,-0.0061426824,-0.016897224,-0.024641465,-0.0845235,-0.026260728,-0.014129737,0.037723307,-0.06328025,0.0104318,-0.061022926,0.021643369