	('prod_a47b11bc-88a3-4ee3-bc22-f67cb2433f67', 'flare-remote-control-car', 'Flare Remote Control Car', '<ul><li><p>High-Speed Drifter: Experience thrilling adventures with our Remote Control Car, which offers dual speed modes, reaching speeds of up to 20 Kmph. Perfect for both kids and adults who love racing!</p></li><li><p>⁠Equipped with LED headlights and tail lights, this car not only ensures visibility during low-light conditions but also adds a sleek and stylish flair to every race.</p></li><li><p>Smooth tires are engineered for the ultimate drifting experience, letting you glide effortlessly around every corner with precision and unmatched style</p></li><li><p>⁠Switch to the grip tires and take speed to the next level, gripping the track with power and precision</p></li></ul><p></p>', 2399, 'https://cdn.toycker.in/products/5e7d5a2f-ced9-4a66-8d08-5519ca64838e.jpeg', 40, '{"compare_at_price": null}', '2026-01-28 05:02:48.054457+00', '2026-01-28 05:02:48.054457+00', 'cat_6441a32d-69cc-448f-97bc-48f3bd11a29b', 'col_a0046b19-1ea9-44b4-a49d-9d8e0314e99c', 'active', NULL, '{https://cdn.toycker.in/products/5e7d5a2f-ced9-4a66-8d08-5519ca64838e.jpeg,https://cdn.toycker.in/products/25d3368d-213d-418c-9c30-99f4b7e77e3c.jpeg,https://cdn.toycker.in/products/e4365454-b04f-43c1-a537-7329dba7be7d.jpeg,https://cdn.toycker.in/products/c9165573-23cc-4ba3-9e52-34a9fa524847.jpeg,https://cdn.toycker.in/products/3db257e8-acdd-4223-8d86-01b26324d832.jpeg}', 'inr', '', '', '', '[-0.005924394,-0.058956493,-0.017807676,-0.033464823,0.06337399,-0.03919078,0.061860748,0.0015030262,0.024892014,-0.009504689,0.061024446,0.019747058,-0.037885815,-0.0044292333,0.059815668,0.0047560143,0.065149195,0.034355868,0.016601892,-0.03465747,0.031586897,0.034570366,0.028605431,-0.007865969,-0.079540014,0.0009908976,0.0018535902,-0.0035161867,-0.028356208,-0.003804144,0.014121001,-0.057543796,-0.013629197,-0.029570937,-0.12458865,-0.013227142,0.0106772985,0.012411802,0.0018755863,0.001201375,-0.090676665