	('prod_b4cffa60-c283-4fb5-9190-33ee86a97728', 'dj-coco-light-music-toy', 'DJ COCO LIGHT & MUSIC TOY', '<p>INTERACTIVE DESIGN: Features a realistic DJ mixer console with turntable controls, sound effect buttons, and vibrant LED display panel for an immersive play experience<br>• LIGHT SHOW: Equipped with colourful LED lights that sync with music and sound effects, creating an exciting visual atmosphere during play<br>• AUDIO FEATURES: Comes with adjustable headphones and multiple sound effects, allowing children to mix and create their own musical combinations<br>• EDUCATIONAL VALUE: Helps develop hand-eye coordination, musical creativity, and basic rhythm skills while providing hours of entertainment<br>• COMPACT CONSOLE: Portable DJ station with easy-to-use controls, perfect for aspiring young DJs to practice their mixing skills</p>', 599, 'https://cdn.toycker.in/products/0e4d023c-4acb-449d-91b1-f7b0be7c6e8a.jpeg', 20, '{"compare_at_price": 699}', '2025-12-28 10:59:10.191653+00', '2025-12-28 10:59:10.191653+00', 'cat_be92f917-7267-474d-9af6-69564702507a', 'col_2c27fef3-dfee-42ef-8d1f-d08d41a2aad7', 'active', 'https://cdn.toycker.in/uploads/dj-coco-light-music-toy/3153ff4a-b7de-42e9-a7cf-41ba4b7b992f.jpg', '{https://cdn.toycker.in/products/0e4d023c-4acb-449d-91b1-f7b0be7c6e8a.jpeg,https://cdn.toycker.in/products/b58eb7c8-3c4d-462d-8e49-78e0a51e63e5.jpeg,https://cdn.toycker.in/products/da9d08f5-a930-4082-890b-0ebadb80ee0b.jpeg,https://cdn.toycker.in/products/fc88acfa-eed4-4bcb-8ff0-dfc8ad799b66.jpeg}', 'inr', NULL, '', '', '[0.028948687,-0.0030375365,0.03399058,0.018696584,0.032011773,-0.011407891,0.067960516,0.030083198,-0.008369037,0.02074194,0.013565549,0.02183001,-0.011485818,-0.07800152,0.06173062,0.013645574,-0.049836896,0.025310274,0.0018361668,-0.039505616,-0.05024826,0.005296157,0.012441203,0.017433297,-0.028951108,-0.004100551,0.026268717,0.019304134,0.011599673,-0.019907532,0.038632635,-0.011121595,-0.0151358405,-0.029369496,-0.10062375,-0.03595691,0.0026