	('prod_1e6b5f78-a18c-4daf-b739-9126beb25053', 'smart-sequence-game', 'Smart Sequence Game', '<ul><li><p>GAMEPLAY OVERVIEW: Sequence combines the excitement of card play with strategic board game elements, creating an engaging experience for 2-12 players</p></li><li><p>FAMILY-FRIENDLY: Perfect for family game nights, this strategy game is suitable for ages 7 and above, fostering critical thinking and social interaction</p></li><li><p>PLAYER COUNT: Accommodates various group sizes from 2 to 12 players, making it versatile for small gatherings or larger parties</p></li><li><p>EDUCATIONAL VALUE: Helps develop strategic thinking, pattern recognition, and planning skills while providing entertainment</p></li><li><p>GAME COMPONENTS: Includes a game board, playing cards, and gaming chips needed for multiple players to enjoy this classic strategy game</p></li></ul>', 299, 'https://cdn.toycker.in/products/679997fd-c843-4c1d-b952-6b5474323091.jpeg', 20, '{"compare_at_price": 399}', '2025-12-28 10:59:19.440472+00', '2025-12-28 10:59:19.440472+00', 'cat_faea0711-a3b3-422e-a496-772919c14df6', 'col_151b58e4-30fe-431c-8a44-bd622c4c1c6e', 'active', 'https://cdn.toycker.in/uploads/smart-sequence-game/01824a9d-c42f-4568-942c-e478867fac72.jpg', '{https://cdn.toycker.in/products/679997fd-c843-4c1d-b952-6b5474323091.jpeg,https://cdn.toycker.in/products/dfc78b0d-396f-4b4c-a254-868bda3f88d2.jpeg,https://cdn.toycker.in/products/e326734f-b824-442b-a6e8-7b08e5a8f547.jpeg}', 'inr', NULL, '', '', '[0.021124816,-0.014840426,0.03356517,-0.012332458,0.0071115107,-0.007057104,0.058271773,0.0402953,-0.0134847835,0.013747172,-0.006210189,0.010310359,0.06468051,-0.05324551,0.043082286,0.026635,0.04390169,0.035321936,0.0005539902,-0.040770724,-0.034317076,0.022748813,0.024146046,0.051934954,-0.0798877,0.035116684,0.02041659,0.03258797,0.033031445,0.008681438,0.0629862,-0.0046589132,-0.0024049485,-0.01351982,0.018024283,-0.051585987,-0.031242423,0.052749556,0.0081500355,-0.10779248,-0.05093077,-0.01754