	('prod_0bedeba3-0e3c-43d8-b0d7-cc165c4afd94', 'music-bus', 'Music Bus', '<ul><li><p>Interactive Learning Experience: This musical bus combines a xylophone, shape sorter, and push &amp; go vehicle, providing endless hours of educational fun for your toddler.</p></li><li><p>Educational Benefits: Enhance your child’s cognitive development, fine motor skills, and sense of rhythm. The xylophone introduces musical concepts while the shape sorter improves hand-eye coordination and shape recognition.</p></li><li><p>Vibrant and Engaging: With bright colors and a friendly animated face, this toy is designed to captivate and entertain, making learning enjoyable.</p></li><li><p>Durable and Safe: Crafted from high-quality, non-toxic materials, ensuring a safe playtime experience for your little one. Perfect Size for Little Hands: Easy to grasp and play with, this toy is designed with your child’s comfort in mind.</p></li><li><p>Abacus for Added Fun: The included abacus on the roof introduces early counting skills, making this toy a comprehensive educational tool.</p></li><li><p>Ideal Gift for Toddlers: Perfect for birthdays, holidays, or just because, this multifunctional bus toy is sure to become a favorite in any toddler’s toy collection.</p></li></ul>', 594, 'https://cdn.toycker.in/products/508d9111-8706-4225-af32-2f6549695cea.jpeg', 20, '{"compare_at_price": 698.97}', '2025-12-28 10:59:16.742694+00', '2025-12-28 10:59:16.742694+00', 'cat_bad350a2-69da-40ad-b948-954075d435d5', NULL, 'draft', 'https://cdn.toycker.in/uploads/music-bus/d0f4e8f6-2711-4e8f-aac9-f408044156d3.jpg', '{https://cdn.toycker.in/products/508d9111-8706-4225-af32-2f6549695cea.jpeg,https://cdn.toycker.in/products/8f409a9c-fbe5-4498-bbf6-609a79ec1d88.jpeg,https://cdn.toycker.in/products/0880c081-7a70-4206-b64b-92ae7bc05033.jpeg,https://cdn.toycker.in/products/e79704b9-5d8d-4e32-bcf5-2bac6a535f2d.jpeg}', 'inr', NULL, '', '', '[-0.0038006473,-0.042253558,0.010012622,0.036405623,0.057600185,0.022447092,0.047030