	('prod_9f16d5f0-4681-4ab5-bd55-69cc74cbd3f8', '24ghz-rc-formula-racing-car-with-spray-effect-and-led-lights-rechargeable-high-speed-remote-control-f1-car-toy', '2.4GHz RC Formula Racing Car with Spray Effect & LED Lights – Rechargeable High-Speed Remote Control F1 Car Toy', '<p>Experience the thrill of racing with this high-performance RC Formula Racing Car! Designed with a sleek F1-style body, this remote control car features realistic spray mist effects, bright LED lights, and smooth 2.4GHz control for precise handling. The durable build ensures long-lasting play, while the rechargeable battery and USB charging cable make it convenient and eco-friendly. With easy forward, backward, left, and right controls, it’s perfect for kids and racing enthusiasts alike. Ideal for indoor and outdoor play, this racing car delivers speed, style, and excitement in every drive! 🚗💨</p>', 849, 'https://cdn.toycker.in/products/d9aa8ac7-d6d9-40c6-bd8c-137fbc8bd914.jpeg', 50, '{"compare_at_price": 1699}', '2026-04-07 12:58:21.546781+00', '2026-04-07 12:58:21.546781+00', 'cat_6441a32d-69cc-448f-97bc-48f3bd11a29b', 'col_a0046b19-1ea9-44b4-a49d-9d8e0314e99c', 'active', NULL, '{https://cdn.toycker.in/products/d9aa8ac7-d6d9-40c6-bd8c-137fbc8bd914.jpeg,https://cdn.toycker.in/products/02b0a504-a443-4479-803a-faa7a093af88.jpeg,https://cdn.toycker.in/products/3195b5ae-c089-4759-acac-c7fd2e58b57a.jpeg,https://cdn.toycker.in/products/5ae0efa5-0d81-4ebd-9bcc-156a01d2273d.jpeg,https://cdn.toycker.in/products/0449a292-367c-4392-9077-ef611613461d.png,https://cdn.toycker.in/products/ac730ade-0225-44ef-a869-8d8d8d53f70b.jpeg}', 'inr', NULL, 'High-speed RC Formula racing car with spray mist effect, LED lights, and smooth 2.4GHz remote control. Rechargeable battery included for endless fun!', 'https://youtu.be/QogGFSviM10', '[0.014490178,-0.0377927,-0.018730594,-0.0150344,0.04961737,-0.01189135,0.0067040417,0.0023857807,0.027119087,-0.0029016084,-0.010913303,0.0072761215,-0.060981937,0.0067333975,0.1087