	('prod_6b70539f-7782-4020-9138-db93906c7562', '1-24-rolls-phantom-alloy-car-model', '1:24 Rolls Phantom Alloy Car Model', '<p>Feature highlights : This&nbsp;1:24 scale Rolls-Royce Phantom&nbsp;diecast model car features a highly detailed design with&nbsp;moveable wheels and six-open functionality, including sound and light effects. Made of premium alloy, it is perfect for collection and play, with dimensions of 21.5*7.5*5cm. The product supports customization options like color and logo, ensuring variety and personalization for users.</p>', 3699, 'https://cdn.toycker.in/products/7c19f516-110b-46fb-9bb7-9accde80c954.jpeg', 50, '{"compare_at_price": 3999}', '2025-12-28 10:59:02.472436+00', '2025-12-28 10:59:02.472436+00', 'cat_6441a32d-69cc-448f-97bc-48f3bd11a29b', 'col_1a985543-7b4d-4da3-8fb6-b52afcdc234c', 'active', 'https://cdn.toycker.in/uploads/1-24-rolls-phantom-alloy-car-model/8b1ab38a-9d25-4455-99f3-36158ea3e028.png', '{https://cdn.toycker.in/products/7c19f516-110b-46fb-9bb7-9accde80c954.jpeg,https://cdn.toycker.in/products/aeacbd3e-c1e7-49ca-b5d4-654205f49e70.jpeg,https://cdn.toycker.in/uploads/1-24-rolls-phantom-alloy-car-model/38578ad8-337f-4428-b157-5b38d40c6ee5.png,https://cdn.toycker.in/products/0a65b11f-2b9e-4a8a-bb5d-243bf4328124.jpeg,https://cdn.toycker.in/products/d9121933-7337-4c65-a658-dcdc5063b51f.jpeg}', 'inr', NULL, '', '', '[-0.02294449,0.0247672,-0.0015540429,-0.004698672,0.03951399,-0.01704237,0.031959325,0.0020820054,-0.031379152,-0.018388849,0.02888177,0.0016354108,0.00090271415,-0.0011391612,0.04704449,0.019137666,0.05634566,0.008740399,0.037920747,-0.045945074,0.10939907,0.04410573,0.019992154,0.002397229,-0.0265939,-0.014928891,-0.014739529,-0.007094928,-0.015687859,0.022629213,0.024663676,0.036466908,0.0056262272,-0.023892388,-0.039360784,0.03335837,-0.011776736,0.05172895,0.029557887,0.14698191,-0.05977026,0.024291465,0.053134013,-0.051873066,0.08062459,-0.08464443,0.089654826,0.007692252,0.03355584,0.016940737,-0.063745886,0.00808319