	('prod_6f710f0c-8a6f-4e26-b564-4a03f2296ac2', 'blaze-storm-gun-with-soft-bullets', 'Blaze Storm Gun with Soft Bullets', '<ul><li><p>For Kids Foam Blaster Soft Bullet Guns are fun for boys with Foam Bullets and Suction Darts for kids. Have a great shooting dart game with this Blaze Storm Manual Soft Bullet Gun. Kids will love to fire soft foam bullets and suction darts and hit imaginary targets.</p></li><li><p>This gun is easy to operate – load the soft bullets or suction darts from the front muzzle, pull the lever at the back, trigger and fire. The magazine can load 4 foam bullets at one time to make the action look all the more real.</p></li></ul>', 280, 'https://cdn.toycker.in/uploads/blaze-storm-gun-with-soft-bullets/a53efad4-1042-474c-8bee-c1b26891fb08.jpg', 20, '{"compare_at_price": 399}', '2025-12-28 10:59:07.636148+00', '2025-12-28 10:59:07.636148+00', 'cat_aef0da25-a920-495d-af0a-9ce132e7c89c', 'col_37cccc82-dee7-4ce4-9d1f-cf6b20863ad0', 'active', 'https://cdn.toycker.in/uploads/blaze-storm-gun-with-soft-bullets/bac4897f-642f-469d-a6b8-20f1d52f1c64.jpg', '{https://cdn.toycker.in/uploads/blaze-storm-gun-with-soft-bullets/a53efad4-1042-474c-8bee-c1b26891fb08.jpg,https://cdn.toycker.in/uploads/blaze-storm-gun-with-soft-bullets/94db6a54-75d5-4e93-8c9a-ed85cb9adcbe.jpg,https://cdn.toycker.in/uploads/blaze-storm-gun-with-soft-bullets/8acd1aac-e934-4f34-985e-c48f32d98cd3.jpg,https://cdn.toycker.in/uploads/blaze-storm-gun-with-soft-bullets/1c242db2-0f40-454a-a720-999386cd047d.jpg,https://cdn.toycker.in/uploads/blaze-storm-gun-with-soft-bullets/af5c6629-6892-42fe-bdba-7f5fce8a0b1a.jpg}', 'inr', NULL, '', '', '[0.022028461,-0.030179951,0.008649301,-0.029861316,0.0077671492,0.012991053,0.016788417,0.037448224,0.027890295,-0.054001696,-0.00052588206,-0.011390046,-0.0056067435,0.008035174,-0.00032536412,-0.020205295,0.08102841,-0.0038044706,-0.0051571783,-0.057553798,-0.048866883,-0.016337318,-0.007318696,0.02319416,0.018958252,0.038201537,0.0071850247,0.003788289,0.034