	('prod_40116f04-2e4b-4dd4-8011-806186a1ee2a', 'happy-bus-ride-on', 'Happy Bus Ride on', '<ul><li><p><strong>Easy Ride:&nbsp;</strong>Perfect for both indoor and outdoor fun, giving your child a sense of freedom and security. With strong wheels and a sturdy body, it’s easy to take wherever you go.</p></li><li><p><strong>Comfortable:</strong>designed for easy on-and-off access, making it convenient for your baby.</p></li><li><p><strong>Safety:</strong>Meets European Standard EN 71 for safety, ensuring your little one enjoys a secure, comfortable ride with an elegant and durable design.</p></li></ul><p>&nbsp;</p>', 1149, 'https://cdn.toycker.in/uploads/happy-bus-ride-on/5cf50ac3-4092-4ca1-98a9-6bc367e1e9b4.webp', 20, '{"compare_at_price": 1599}', '2025-12-28 10:59:14.633954+00', '2025-12-28 10:59:14.633954+00', 'cat_509ec14c-adb8-4411-aa7d-8c613d501c7a', 'col_d27f16c3-8935-41d9-90af-5895ffef1e0c', 'active', 'https://cdn.toycker.in/uploads/happy-bus-ride-on/5cf50ac3-4092-4ca1-98a9-6bc367e1e9b4.webp', '{https://cdn.toycker.in/uploads/happy-bus-ride-on/5cf50ac3-4092-4ca1-98a9-6bc367e1e9b4.webp,https://cdn.toycker.in/uploads/happy-bus-ride-on/abeaebb5-d05f-4e79-ace8-ea2d92ce83e5.webp,https://cdn.toycker.in/uploads/happy-bus-ride-on/8440a888-beec-4e7d-8f3d-abefb61dbf1f.webp,https://cdn.toycker.in/uploads/happy-bus-ride-on/9604b9b8-2c33-44da-9132-7a47af5263a7.webp,https://cdn.toycker.in/uploads/happy-bus-ride-on/9e7a48ea-5545-4d5c-9182-302bb7d92e6c.webp,https://cdn.toycker.in/uploads/happy-bus-ride-on/151addee-8656-4669-8cc8-c3b08a7b0b83.webp,https://cdn.toycker.in/uploads/happy-bus-ride-on/654f4538-057c-4a61-96fb-ac788c931868.webp,https://cdn.toycker.in/uploads/happy-bus-ride-on/bacbc03a-e61f-4c0b-b9ad-ebd53affa488.webp}', 'inr', NULL, '', '', '[0.016148772,-0.056911167,0.035284244,0.006449552,0.0062640766,0.03406551,0.07762068,0.035774317,-0.032193884,0.03905768,-0.020035597,-0.0029480231,0.11522826,0.03839869,0.047514252,-0.10692713,-0.0031693464,0.044660542,-0.07699039,