	('prod_b88f833f-e0b2-4952-bcf7-10df1d8e4f66', 'deform-plane', 'Deform Plane', '<ul><li><p>✅ 2-in-1 Transforming Fun – Switch between Dinosaur Mode and Fighter Jet Mode, offering double the excitement in one toy!</p></li><li><p>✅ Realistic Spray Effect – Features an interactive spray mist that enhances the action, making playtime more engaging.</p></li><li><p>✅ Perfect for Dinosaur Lovers – Designed for kids who love dinosaurs, airplanes, and fighter jets, encouraging creative storytelling.</p></li><li><p>✅ Durable &amp; Safe Design – Made from high-quality, non-toxic ABS plastic, ensuring long-lasting and safe play for children.</p></li><li><p>✅ Easy to Use – Simple transformation between helicopter, plane, and dinosaur forms, perfect for young hands to operate.</p></li><li><p>✅ Ideal Gift for Kids – A fantastic birthday, holiday, or special occasion gift for boys and girls who love dinosaurs and vehicles.</p></li></ul>', 699, 'https://cdn.toycker.in/uploads/deform-plane/47bcddad-bc91-4304-acd6-40cd770592cc.jpg', 20, '{"compare_at_price": 999}', '2025-12-28 10:59:09.505248+00', '2025-12-28 10:59:09.505248+00', 'cat_65d2f8ce-019c-463c-b266-45616a6d092b', 'col_4d51f80f-e115-49f5-9990-8277b8b5a8b3', 'active', 'https://cdn.toycker.in/uploads/deform-plane/58ef7236-0d1e-4278-8875-e354bf8c01ab.jpg', '{https://cdn.toycker.in/uploads/deform-plane/47bcddad-bc91-4304-acd6-40cd770592cc.jpg,https://cdn.toycker.in/uploads/deform-plane/2c31336c-cde0-4c58-a7be-5117fd731084.jpg,https://cdn.toycker.in/uploads/deform-plane/c74bb7ca-df3b-434b-a189-e0eee5d7c858.jpg,https://cdn.toycker.in/uploads/deform-plane/23a0ba96-c36d-4ce5-bace-3b5d13e79c15.jpg}', 'inr', NULL, '', '', '[0.028841993,-0.014629371,0.031782024,-0.01185217,0.05627352,-0.05278488,-0.0058126547,0.028301666,0.03410263,-0.024645822,0.015888924,-0.003191522,0.045781054,-0.043010797,-0.0070007895,-0.031502515,0.051953558,0.026249459,-0.043582458,-0.044575736,-0.034577314,-0.0014658252,0.028787604,0.024827741,-0.0072880564,0.0