	('prod_cfca1894-1b93-437e-9aa6-f4dc913c8d8f', 'pencil-pouch-cartoon-big-size', 'Pencil Pouch Cartoon Big Size', '<ul><li><p>✔ EVA MATERIAL &amp; EMBROSSED HARDTOP: This carrying pencil case is made of durable and stylish EVA material, compressive, shockproof, waterproof, all-round protection of stationery. Each of cute pencil case comes with an embossed Space Astronaut pattern on the front that gives a vivid look and make your kid happy.</p></li><li><p>✔ PREMIUM QUALITY PENCIL CASE: Pen bag with compartments for better organization. Different compartments make arrangement easier. You can always find right places for your color pens, pencils, eraser, markers and other items. Wide open zipper, convenient to take stationery out.</p></li><li><p>✔ LARGE STORAGE CAPACITY: Durable wide zipper for easy top or bottom closure, ready for every new adventure; Portable travel size makes it very easy and convenient to carry anywhere. Large capacity, wide open mesh pockets allowing to store a variety of items.</p></li><li><p>✔ MULTIPURPOSE: The ultra-cute and stylish pencil cases are here to make a statement, they can be used to carry pencil, pens, colors, other stationary or used as a chic multipurpose travel pouch for storing makeup, essentials, pens etc. It will make the kids stand out in the classroom. Outer Material: Canvas; Inner Material: Net velvet.</p></li></ul>', 299, 'https://cdn.toycker.in/products/9d9dde91-9e1b-4536-adeb-283bcf03f281.jpeg', 20, '{"compare_at_price": 599}', '2025-12-28 10:59:17.753934+00', '2025-12-28 10:59:17.753934+00', NULL, 'col_5952bc0e-92a8-4ba5-8232-045f9bb7faa7', 'active', 'https://cdn.toycker.in/uploads/pencil-pouch-cartoon-big-size/e458a654-065d-4341-9774-b01cf2c8eaa9.jpg', '{https://cdn.toycker.in/products/9d9dde91-9e1b-4536-adeb-283bcf03f281.jpeg,https://cdn.toycker.in/products/9ec60843-2033-40c7-b26b-cf56cde80cd5.jpeg,https://cdn.toycker.in/products/b2ff8525-7cce-49ef-adfe-9042005180fe.jpeg,https://cdn.toycker.in/products/354c0052-8159-47b4-b0e4-486ed1522b0d.jpeg}', 'inr', NULL, '', '', '[-0.031226879,0.060672484,0.026331931,-0.00032051158,0.069900095,0.01534001,0.067517996,0.0041154525,-0.023750868,0.006425543,-0.011214741,-0.05804592,-0.0138073955,-0.022402309,0.054459706,-0.011035454,-0.06452365,-0.0075624827,-0.013344171,-0.013467499,-0.09744029,-0.020618176,0.00071618793,0.023342906,-0.0010710034,0.020068366,-0.00088309695,0.05098187,0.008829905,-0.03858801,-0.045284703,-0.0039380514,0.0054207854,0.009418444,-0.04203309,-0.03237818,-0.019833427,0.01542055,0.009313861,0.012367595,-0.007501077,-0.034386445,0.077931605,0.019053958,-0.022331126,-0.045042437,0.011093455,-0.008926377,-0.01877257,-0.007934097,0.008728344,0.03368967,-0.008775061,0.019432355,-0.036429748,-0.015076541,-0.021827439,-0.05844574,-0.050469615,-0.019957596,0.04447637,-0.013833325,-0.06007402,0.012697423,0.023820698,-0.005416332,0.036475223,0.07095329,-0.027745187,-0.018852534,-0.05569551,-0.05426824,-0.03343501,0.007821014,0.027719233,0.022928374,0.015461585,-0.039707366,-0.03704325,0.06492218,-0.022041457,-0.052980214,0.035426464,-0.06810205,0.00016589124,-0.021180727,-0.049522836,-0.0005306674,0.014616903,0.07591238,-0.04925999,0.013415755,-0.32967636,0.073013335,-0.015837336,0.013757938,0.03790734,0.011549794,-0.016569367,0.16780442,0.0013083947,-0.037135407,-0.03577372,0.027104052,-0.04029022,-0.010345394,0.008690205,-0.029071875,0.040571257,0.047444314,0.0138725275,0.054547343,-0.005609684,-0.029458893,-0.0036375432,0.027712496,0.00090028346,0.0110445535,-0.0047315154,0.039481204,-0.00013704761,0.023473777,-0.0063472646,0.03999678,0.019370187,0.040059123,0.037804056,-0.0056287427,-0.012064464,-0.04649255,0.022665102,-0.025286403,-0.051524002,0.07552633,-0.0809188,-0.04996202,-0.014708265,0.04654101,-0.018735006,-0.0071565467,0.039483014,-0.027313327,0.11421057,0.024582578,-0.008832951,0.0079812445,0.08592791,-0.030154038,-0.019932171,0.022163488,-0.048693433,0.062928,-0.08855942,-0.030896721,-0.023930216,-0.023994625,0.0