	('prod_222c08d1-57d0-46c9-96a4-2d14903fb944', 'mclaran-toy-car-132-scale-car', 'McLaran Toy Car 1:32 Scale Car', '<ul><li><p>Realistic Lights &amp; Engine Sound: Features front and tail lights that activate along with engine sounds when the doors are opened, giving kids a lifelike driving experience.</p></li><li><p>Premium Die-cast Design: Crafted from high-quality alloy metal with attention to detail, this 1:32 scale McLaren 765LT model offers a sleek and durable finish ideal for play and display.</p></li><li><p>Openable Doors &amp; Pull-Back Action: The doors open smoothly, and the pull-back mechanism adds interactive fun, making it engaging for young car lovers.</p></li><li><p>Safe &amp; Kid-Friendly: Designed for children aged 3 and up, this toy car includes rubber tires for a smooth ride and a sturdy body for safe indoor play.&nbsp;</p></li><li><p>Great Gift &amp; Collectible: Whether for a birthday, return gift, or a collector’s showcase, this model car is a perfect pick for kids and car enthusiasts a like.</p></li></ul><p></p>', 999, 'https://cdn.toycker.in/products/fde3316f-8af5-456f-a03d-682f69f23d86.jpeg', 49, '{"compare_at_price": 1399}', '2025-12-28 10:59:16.210065+00', '2025-12-28 10:59:16.210065+00', 'cat_6441a32d-69cc-448f-97bc-48f3bd11a29b', 'col_1a985543-7b4d-4da3-8fb6-b52afcdc234c', 'active', 'https://cdn.toycker.in/uploads/mclaran-765lt-toy-car-1-32-scale-car/78bd81be-4289-42d3-9314-f675c4aee3e5.webp', '{https://cdn.toycker.in/products/fde3316f-8af5-456f-a03d-682f69f23d86.jpeg,https://cdn.toycker.in/products/0fe92f5b-d545-4038-a7f5-804563c7c039.jpeg,https://cdn.toycker.in/products/a8cc9f9c-e3e8-4039-a5c5-37fccd15646b.jpeg}', 'inr', NULL, '', '', '[-0.0011595414,-0.032328524,0.017890748,0.0018236563,0.06397814,-0.018162824,0.048706174,0.009859423,0.06925441,0.0042863446,0.02272857,0.0045455587,-0.054880533,-0.054137114,0.048046965,-0.021290597,0.033616114,0.00628447,0.016573679,-0.026386013,0.0680665,0.032998323,0.008552089,0.027109025,-0.04965159