	('prod_a75c8f19-0e71-4216-88df-ae41380db036', 'range-rover-metal-diecast-car-model-car', 'Range Rover Metal Diecast Car Model Car', '<p>Introducing the epitome of speed and style: the Diecast Road Racing Car Collection. Crafted with precision and passion, these diecast model cars are the embodiment of automotive excellence, designed to satisfy the cravings of both collectors and enthusiasts alike. Constructed from high-quality metal, each diecast car in this collection boasts unparalleled durability and authenticity. From the sleek curves of the Lamborghini to the luxurious lines of the Mercedes Car, every detail has been meticulously replicated to capture the essence of these iconic vehicles.&nbsp;</p>', 999, 'https://cdn.toycker.in/products/946cd0c1-fc40-4b47-b113-d2fbd50006d7.jpeg', 20, '{"compare_at_price": 1500}', '2025-12-28 10:59:19.047179+00', '2025-12-28 10:59:19.047179+00', 'cat_6441a32d-69cc-448f-97bc-48f3bd11a29b', 'col_1a985543-7b4d-4da3-8fb6-b52afcdc234c', 'active', 'https://cdn.toycker.in/uploads/range-rover-metal-diecast-car-model-car/b44d2cf6-ee27-42c1-8cfc-a9f7ef740740.jpg', '{https://cdn.toycker.in/products/946cd0c1-fc40-4b47-b113-d2fbd50006d7.jpeg,https://cdn.toycker.in/products/ad9b2360-83e0-4617-9ca3-6e4efdb859e3.jpeg,https://cdn.toycker.in/products/be36d54e-b5c1-40fb-9e74-9138f24d99e5.jpeg,https://cdn.toycker.in/products/cf529304-b213-4799-871f-3226712d8993.jpeg}', 'inr', NULL, '', '', '[-0.020064278,0.041685116,0.03294868,0.0059797955,0.04954168,-0.005323022,0.06684719,-0.002541078,-0.016534634,0.0023836168,0.031125214,0.013887892,0.026227877,-0.014364055,0.06862488,0.058146518,0.04166724,0.015805162,0.036095332,-0.048026532,0.08780058,0.053123634,0.011511497,-0.018196974,-0.030093512,-0.007683112,0.001525735,0.0009809327,-0.026499629,-0.01516454,-0.03401533,0.019495878,0.02390045,-0.026301643,-0.040820297,0.009589106,0.021077376,0.032481335,-0.014146222,0.08754425,-0.05103255,0.06016795,0.03895139,-0.041900225,0.011639918,-0.12873189,0.0606