	('prod_75dbc755-c52a-4f05-a0f1-7f9e17c9eea7', 'crinkling-fabric-book-6-part-2', 'Crinkling Fabric Book 6 ( part 2 ) ', '<p><strong>Fuel Curiosity &amp; Brain Development:</strong> Our "My First Library" set is specifically engineered to engage a child''s developing brain. By combining vibrant visuals with a unique "crinkle" texture, these books stimulate the <strong>Occipital Lobe</strong> (visual processing) and the <strong>Parietal Lobe</strong> (sensory perception), making learning an interactive experience.<br></p><p><strong>The Complete Set Includes 6 Essential Topics:</strong></p><p></p><ol><li><p><strong>Alphabets:</strong> Introduction to letters with fun illustrations.</p></li><li><p><strong>Numbers:</strong> Basic counting made easy.</p></li><li><p><strong>Opposites:</strong> Understanding different concepts through play.</p></li><li><p><strong>Community Helpers:</strong> Learning about the heroes in our society.</p></li><li><p><strong>Habits Guide:</strong> Encouraging positive daily routines.</p></li><li><p><strong>India’s National Symbols:</strong> A colorful guide to monuments and culture.<br></p></li></ol><p><strong>Why Choose EduBeels Fabric Books?</strong></p><p></p><ul><li><p><strong>Safety First:</strong> Made from high-quality, non-toxic fabric. It is "Certified Baby Safe," so you don''t have to worry if your little one puts it in their mouth.</p></li><li><p><strong>Interactive Sound:</strong> Every page features a crinkle paper inner layer that mimics the sound of rustling paper, keeping babies engaged for hours.</p></li><li><p><strong>Durable &amp; Washable:</strong> Unlike paper books, these cannot be torn. They are bite-resistant and can be machine or hand-washed to maintain hygiene.</p></li><li><p><strong>Portable Design:</strong> Each book features a small hanging loop, making it easy to attach to strollers, car seats, or diaper bags.<br></p></li></ul><p><strong>Specifications:</strong></p><p></p><ul><li><p><strong>Material:</strong> Premium Soft Cloth</p></li><li><p><strong>Contents:</strong> 6 Books + 1 Designer Box</p></li><li><p><strong>Features:</strong> Crinkle Sound, High-Resolution Printing, Lightweight</p></li></ul><p></p>', 549, 'https://cdn.toycker.in/products/448a52f7-2b3d-4b5f-b997-97c5c92370f0.jpeg', 50, '{"compare_at_price": 748.98}', '2026-03-11 11:56:17.509839+00', '2026-03-11 11:56:17.509839+00', 'cat_94b4dcf4-745a-4430-a23c-e10f79594fa6', 'col_151b58e4-30fe-431c-8a44-bd622c4c1c6e', 'active', NULL, '{https://cdn.toycker.in/products/448a52f7-2b3d-4b5f-b997-97c5c92370f0.jpeg,https://cdn.toycker.in/products/4010174b-1093-47b6-8ea2-775916533d48.jpeg,https://cdn.toycker.in/products/aefe0c79-1e33-4b16-81df-4419f3701cf6.jpeg,https://cdn.toycker.in/products/8ea212ed-3793-459c-aa2e-cea1d2c5e498.jpeg,https://cdn.toycker.in/products/1e9e562e-c381-4605-989b-2a0dab8a1d1c.jpeg}', 'inr', NULL, 'Give your child a head start with this premium set of 6 soft, crinkly fabric books. Designed to stimulate sensory development through touch and sound, these tear-proof and washable books cover essential early learning topics like Alphabets, Numbers, and Habits.INSERT INTO "public"."product_variants" ("id", "title", "sku", "barcode", "price", "inventory_quantity", "manage_inventory", "allow_backorder", "product_id", "options", "metadata", "created_at", "updated_at", "original_price", "compare_at_price", "image_url") VALUES
