	('prod_c1ebd26a-a5fb-484f-b2cd-118e656417b7', 'architect-brick-toys-premium-quality', 'Architect Brick Toys – Premium Quality', '<ul><li><p>Triple the Adventures: With a whopping 145+ pieces, you can assemble three fantastic vehicles – a sleek Helicopter, a speedy Plane, or a versatile Hovercraft. Change it up whenever you’re ready for a new journey!</p></li><li><p>Guided Assembly: No worries if you’re new to brick-building. This set includes an easy-to-follow manual with step-by-step instructions for all three vehicles. You’ll be an expert pilot in no time!</p></li><li><p>Built to Last: Safety is paramount. These bricks are durable and meet the highest quality and safety standards, ensuring countless hours of secure play.</p></li><li><p>STEM-Powered Play: As you construct these flying and floating marvels, you’re also gaining valuable STEM skills. It’s like a science and engineering lesson with a side of adventure!</p></li></ul>', 849, 'https://cdn.toycker.in/uploads/architect-brick-toys-premium-quality/af27282c-244d-4893-925b-e115c0d7eadf.jpg', 20, '{"compare_at_price": 999}', '2025-12-28 10:59:04.665369+00', '2025-12-28 10:59:04.665369+00', NULL, 'col_854e0262-cc7f-4089-86cb-eac2e3971e0b', 'active', 'https://cdn.toycker.in/uploads/architect-brick-toys-premium-quality/af27282c-244d-4893-925b-e115c0d7eadf.jpg', '{https://cdn.toycker.in/uploads/architect-brick-toys-premium-quality/af27282c-244d-4893-925b-e115c0d7eadf.jpg,https://cdn.toycker.in/uploads/architect-brick-toys-premium-quality/473fef58-e15b-4cfc-8f0e-a5da19f5bd7a.jpg,https://cdn.toycker.in/uploads/architect-brick-toys-premium-quality/27af1277-df48-4db3-ae5a-bf13e8d3b06c.jpg,https://cdn.toycker.in/uploads/architect-brick-toys-premium-quality/e9550399-0ec2-4edc-a198-b3c8d534026c.jpg,https://cdn.toycker.in/uploads/architect-brick-toys-premium-quality/e79bb92d-4dcf-4b3a-8fe3-c66fbc8d7d2a.jpg,https://cdn.toycker.in/uploads/architect-brick-toys-premium-quality/cca20563-f9d8-45a6-8693-93e54d28f2ca.jpg}', 'inr',