	('prod_47eaf005-16a5-4c1d-9a33-465939d70d61', 'rc-jcb-excavator-toy', 'RC JCB Excavator Toy', '<p>Realistic Design: This remote-controlled excavator toy features a highly detailed and realistic construction vehicle design, complete with a movable arm, bucket, and treaded wheels.<br>Enjoy the convenience of wireless control with the included controller, allowing you to operate the excavator from a distance.</p><p>Experience the thrill of digging and shovelling with the excavator’s articulated arm and bucket movement.</p>', 999, 'https://cdn.toycker.in/uploads/rc-jcb-excavator-toy/67065ecf-605a-43a0-b38c-e7adc0d93733.jpg', 20, '{"compare_at_price": 1299}', '2025-12-28 10:59:18.944766+00', '2025-12-28 10:59:18.944766+00', 'cat_65960efd-3436-4822-89e6-6043c99610c3', 'col_a0046b19-1ea9-44b4-a49d-9d8e0314e99c', 'active', 'https://cdn.toycker.in/uploads/rc-jcb-excavator-toy/67065ecf-605a-43a0-b38c-e7adc0d93733.jpg', '{https://cdn.toycker.in/uploads/rc-jcb-excavator-toy/67065ecf-605a-43a0-b38c-e7adc0d93733.jpg,https://cdn.toycker.in/uploads/rc-jcb-excavator-toy/e1003a12-a453-4256-af6e-f6d8ab9cef19.jpg,https://cdn.toycker.in/uploads/rc-jcb-excavator-toy/0d3c1ad1-fa52-4580-8136-1302d5fa4f90.jpg}', 'inr', NULL, '', '', '[0.0105386805,-0.019217566,-0.024908507,0.014237643,0.0025407348,0.010149245,0.07278128,0.055635706,0.009006367,0.013900996,-0.007953494,0.017647766,0.032727074,0.032101434,0.012268014,-0.008095281,0.04937752,0.0023883076,-0.036121223,-0.03983464,0.035642702,-0.021227967,-0.024625173,0.05301123,-0.02800301,0.045913674,0.022459775,-0.013762489,-0.0002949318,-0.07701448,0.033355683,-0.03377785,0.014294391,0.06555808,-0.04188428,-0.04954411,-0.016689138,0.0012794673,0.016446475,-0.078053,-0.002512119,0.027627401,0.00083602645,0.014895389,0.022486178,-0.07189648,0.020464886,-0.016566603,0.012506475,-0.010181777,0.023593914,-0.019666016,-0.037935328,0.02833489,0.028227862,-0.006704739,-0.045107644,0.017820345,0.034501318,-0.029910333,0.05361283,-0.030192303,-0.0297