	('prod_f38f3a06-a7ff-4095-a0c0-c1eeec2f2978', 'rechargeable-educational-phone-toy-kids', 'Rechargeable Educational Mobile Phone Toy Kids', '<p>Blast off into learning and fun with this engaging kids'' toy smartphone! Designed to look just like a real phone, it features a vibrant, interactive screen with colorful icons for music, stories, numbers, shapes, and more. Little astronauts will love exploring the engaging activities, while the space-themed case sparks imagination. It''s the perfect toy to introduce early learning concepts and keep tiny hands happily entertained!</p>', 399, 'https://cdn.toycker.in/products/0f9581d8-ed85-4d67-b6dc-4487bd326394.png', 200, '{"compare_at_price": 390}', '2025-12-28 10:59:20.065731+00', '2025-12-28 10:59:20.065731+00', 'cat_b5e5b995-e9b1-49ee-913a-a07cb90b83e4', 'col_2c27fef3-dfee-42ef-8d1f-d08d41a2aad7', 'active', 'https://cdn.toycker.in/uploads/rechargeable-educational-phone-toy-kids/24b49040-16d6-42e5-a32b-bc09f61e7694.jpg', '{https://cdn.toycker.in/products/0f9581d8-ed85-4d67-b6dc-4487bd326394.png,https://cdn.toycker.in/products/39fa6094-d2a0-45fa-8d99-7933325e06ae.png,https://cdn.toycker.in/products/6337b79f-6684-485b-ba29-9b9f9e5873d9.jpeg,https://cdn.toycker.in/products/3cfed435-73bf-4791-9be0-1da3c9508253.jpeg,https://cdn.toycker.in/products/9eb7cee9-4d33-4add-9faf-7d815967fc41.png,https://cdn.toycker.in/products/4c54d7ea-ceef-4777-a531-0173549c1e7f.png,https://cdn.toycker.in/products/9a13d5d9-ef22-4040-b691-2a86edb2f099.jpeg}', 'inr', NULL, '', '', '[-0.01373184,0.064786695,-0.00011572022,0.035661787,0.055090945,-0.012917771,0.018493017,0.0014964592,0.010852301,0.009152644,-0.01943531,0.020705257,-0.010278879,-0.013012985,0.014186856,-0.0051653343,-0.038211666,-0.00017334554,0.021197956,-0.072734736,0.08282158,-0.008379022,0.021596016,0.014337852,-0.006792772,0.056690123,0.013921298,-0.024787316,0.021674287,0.009654157,-0.017125512,0.008128303,-0.03787326,0.02775867,-0.020439077,-0.08637143,0.012214659,-0.0025232146,0.01