	('prod_cb510c25-4605-4077-8805-baf47c235ed2', '118-difender-car', 'Dodge Mini Metal Car', '<ul><li><p>Rev up the excitement with a collection of Hot Wheels vehicles inspired by the Fast &amp; Furious franchise.</p></li><li><p>Each supercharged 1:64 scale vehicle is ready for action right out of the pack!</p></li><li><p>Fire up their need for speed and competition with this iconic collection!</p></li><li><p>The stylish decos of these big-screen replicas are perfect for play or display.</p></li><li><p>Fans of street racing, muscle cars, trucks, tanks, and followers of the Fast &amp; Furious phenomenon are going to want to collect them all!</p></li></ul>', 160, 'https://cdn.toycker.in/uploads/118-difender-car/468c6502-ac37-425f-a0bc-d12a0b6e0036.jpg', 20, '{"compare_at_price": 199}', '2025-12-28 10:59:03.801425+00', '2025-12-28 10:59:03.801425+00', 'cat_6441a32d-69cc-448f-97bc-48f3bd11a29b', 'col_3e7482c6-92fa-4798-9d71-b92e16e3f43b', 'active', 'https://cdn.toycker.in/uploads/118-difender-car/dd9fc23b-9c1f-4328-b85b-3be45ae7d9ff.jpg', '{https://cdn.toycker.in/uploads/118-difender-car/468c6502-ac37-425f-a0bc-d12a0b6e0036.jpg,https://cdn.toycker.in/uploads/118-difender-car/e415a60e-9708-4c66-9ff9-57b06ca46b9c.jpg,https://cdn.toycker.in/uploads/118-difender-car/9d3724cf-9b58-4557-b9fa-42e3d29cbf04.jpg,https://cdn.toycker.in/uploads/118-difender-car/6320ccf6-2e1a-4e5f-8e91-700da5458e82.jpg}', 'inr', NULL, '', '', '[0.024980815,0.0057368707,-0.028274458,-0.02900656,0.044854667,-0.022686178,0.047675237,0.03542039,0.036530677,-0.013184147,0.042640194,0.0024449846,0.013108243,0.00034228468,0.050385542,0.024077535,0.11661839,0.036461297,0.015119305,-0.008247647,0.052057166,0.017924905,0.08000869,-0.0036594896,-0.009037607,0.0025800504,-0.0246517,-0.017314913,-0.010265235,-0.028902544,0.03145858,-0.01952834,0.009347059,-0.009473836,0.0044465447,0.0018797958,-0.011140194,0.024543177,0.023364361,0.06184246,-0.022930097,0.04368453,-0.026186358,-0.031257678,0.025416778,-0.08284054,