	('prod_86011323-1f26-4d7e-b783-5134d9faedac', 'adjustable-musical-baby-walker-with-activity-board-and-drawing-pad-for-kids', 'Adjustable Musical Baby Walker with Activity Board & Drawing Pad for Kids', '<p>Make your baby’s first steps fun and educational with this Adjustable Musical Baby Walker. Designed with multiple engaging features, this walker supports walking while boosting learning and creativity.</p><p>It comes with a built-in mini piano, interactive toy phone, and colorful activity panel that keeps kids entertained for hours. The magnetic drawing board allows children to draw, write, and explore their creativity. The smooth and sturdy wheels ensure safe movement, while the strong handle provides excellent grip for beginners.</p><p>Crafted with premium-quality plastic and a stable structure, this walker helps improve balance, coordination, and motor skills. Perfect for toddlers, it combines playtime and learning in one exciting product.</p>', 1999, 'https://cdn.toycker.in/products/afc48b74-1271-45d7-8c34-edcb80b32da3.jpeg', 50, '{"compare_at_price": 2999}', '2026-04-17 10:43:28.951345+00', '2026-04-17 10:43:28.951345+00', 'cat_ef2b01d6-df1a-49cd-bef4-17db609f10b4', 'col_e5a76b8c-59ac-4ec2-881f-8f2472259122', 'active', NULL, '{https://cdn.toycker.in/products/afc48b74-1271-45d7-8c34-edcb80b32da3.jpeg,https://cdn.toycker.in/products/ac481aa8-1707-4e42-98df-fdabfc035835.jpeg,https://cdn.toycker.in/products/d1026b41-c88f-4970-b6ca-280060d33c62.jpeg,https://cdn.toycker.in/products/651faf67-373f-43df-85c2-99a59b9b5e64.jpeg,https://cdn.toycker.in/products/e1695f16-0d81-41fb-8d2f-9c588cb102dd.jpeg}', 'inr', NULL, 'Interactive baby walker with music, learning toys, mini piano, and magnetic drawing board. Helps babies learn walking while playing and developing skills.', 'https://youtu.be/MLyGCT_UccA', '[0.016016914,-0.026795587,0.054434866,0.021059945,0.0057861567,-0.009284201,0.04323952,0.05205137,0.0057345773,0.005475649,-0.0023577127,-0.03544081,-0.020996734,-0.032