	('prod_b2a99e54-cb6f-490b-9478-97915d0aefe2', 'bafna-jumping-dino-key-toy', 'Bafna Jumping Dino Key Toy', '<p>Pcs Jumping Wind Up Toys For Babies Key Operated Crawling Walking Toy Set for Kids - Fun &amp; Interactive Animal Toy Set for Boys &amp; Girls.Interactive Playtime: This set of 3 wind-up toys includes a jumping bird, rabbit, and animal, providing endless fun and engagement for babies and kids. • Durable Construction: Made from high-quality, non-toxic materials, these toys are built to withstand rough play while ensuring your child''s safety.These wind-up toys are not only fun but also help develop fine motor skills, hand-eye coordination, and stimulate creativity and imagination in young minds. • Versatile Gift: Perfect for birthdays, festivals, or as a surprise treat, this animal toy set is sure to delight boys and girls alike.The lightweight and small size of these toys make them easy to carry around, perfect for keeping kids entertained on the go.</p>', 99, 'https://cdn.toycker.in/uploads/bafna-jumping-dino-key-toy/cbee0b31-3ca4-444e-9870-396c8e5eaca9.webp', 20, '{"compare_at_price": null}', '2025-12-28 10:59:05.702733+00', '2025-12-28 10:59:05.702733+00', NULL, 'col_854e0262-cc7f-4089-86cb-eac2e3971e0b', 'active', 'https://cdn.toycker.in/uploads/bafna-jumping-dino-key-toy/cbee0b31-3ca4-444e-9870-396c8e5eaca9.webp', '{https://cdn.toycker.in/uploads/bafna-jumping-dino-key-toy/cbee0b31-3ca4-444e-9870-396c8e5eaca9.webp,https://cdn.toycker.in/uploads/bafna-jumping-dino-key-toy/bcd85e51-9266-4d8e-a2c1-e671eb5d89a4.webp}', 'inr', NULL, '', '', '[0.0137494495,-0.030524366,-0.021431835,-0.0077179587,0.038137067,-0.0034733037,0.06947242,0.0072426167,0.030968646,0.033609875,-0.0141546605,0.02355183,-0.032961424,0.019887486,-0.0055644647,-0.017964039,0.036600433,0.007853227,0.0003225805,0.015545601,-0.13758515,-0.006563136,0.006065566,0.044757877,-0.024285117,0.014534246,-0.039403703,-0.030140076,-0.020574573,-0.059385307,0.015650937,0.0145378485,-0.023143193,0.047