	('prod_9787d43b-b9f6-4747-bb8c-a1b5fc4111fe', '360-degree-rotation-with-light-music', 'Hero Avengers Car Rock Crawler', '<ul><li><p>Dual Speed Thrills: Experience the excitement with 2 speeds – Normal and Turbo for versatile off-road adventures</p></li><li><p>Remote Dominance: Command from a distance with the 2.4GHz remote, boasting a range over 75 feet. Extended Playtime: Enjoy over 60 minutes of non-stop action thanks to the in-built lithium battery.</p></li><li><p>Effortless Recharging: C-Type rechargeable design with an included cable for convenient and eco-friendly recharging.</p></li><li><p>Headlights Galore: Navigate with ease using 4 different headlight modes for enhanced visibility.</p></li><li><p>Item Type Name: Toy Car</p></li></ul>', 1599, 'https://cdn.toycker.in/uploads/360-degree-rotation-with-light-music/0c2b0002-ec26-4078-9866-1ac9b0753369.png', 50, '{"compare_at_price": 1999}', '2025-12-28 10:59:03.062771+00', '2025-12-28 10:59:03.062771+00', 'cat_6441a32d-69cc-448f-97bc-48f3bd11a29b', 'col_1a985543-7b4d-4da3-8fb6-b52afcdc234c', 'active', 'https://cdn.toycker.in/uploads/360-degree-rotation-with-light-music/4946752f-77e6-44dd-8eb2-d9d31689b603.png', '{https://cdn.toycker.in/uploads/360-degree-rotation-with-light-music/0c2b0002-ec26-4078-9866-1ac9b0753369.png,https://cdn.toycker.in/uploads/360-degree-rotation-with-light-music/9af84515-1072-4501-b182-5f616c0cc71e.jpg,https://cdn.toycker.in/uploads/360-degree-rotation-with-light-music/3ac03bf8-bc08-43b4-88ed-7bce6a31a7ae.jpg,https://cdn.toycker.in/uploads/360-degree-rotation-with-light-music/6d227846-1a2d-4739-9862-46cd34aba523.jpg}', 'inr', NULL, '', '', '[0.031458832,-0.014723833,0.010424063,0.033938617,0.014304014,-0.031431615,0.045033842,0.03400084,0.036909554,-0.015291267,0.052865226,0.028621223,-0.010493095,-0.005190011,0.035139803,0.009978836,0.13561516,0.018429723,-0.009789056,-0.036762334,0.017824048,0.043159924,0.027728915,0.0029885224,-0.035632893,0.039301317,-0.025131902,-0.022059537,-0.054