	('prod_ce2e2ee5-6cb8-493f-8781-a6ae7c407d6d', 'plastic-golf-set-with-golf-sticks-platform-cup-2-balls-kids-boys-girls-realistic-golf-game-set-for-both-indoor-outdoor-gamemulticolor-pack-of-1', 'Plastic Golf Set with Golf Sticks, Platform Cup & 2 Balls Kids Boys', '<p>Kids golf set designed to introduce young ones to the fun of golfing in an engaging way. • Indoor/Outdoor Play: Suitable for both indoor and outdoor play, allowing kids to practice their swing anywhere. • Helps kids develop hand-eye coordination, focus, and an interest in sports from an early age. The set includes a durable golf club, a ball, and a target ring, ensuring hours of fun-filled practice sessions. Crafted with high-quality materials, this golf set is suitable for both indoor and outdoor use</p>', 518, 'https://cdn.toycker.in/products/e0cb83e4-e719-48f2-a3f2-6e1944b816b6.jpeg', 20, '{"compare_at_price": 699}', '2025-12-28 10:59:16.93927+00', '2025-12-28 10:59:16.93927+00', 'cat_94b4dcf4-745a-4430-a23c-e10f79594fa6', 'col_151b58e4-30fe-431c-8a44-bd622c4c1c6e', 'active', 'https://cdn.toycker.in/uploads/plastic-golf-set-with-golf-sticks-platform-cup-2-balls-kids-boys-girls-realistic-golf-game-set-for-both-indoor-outdoor-gamemulticolor-pack-of-1/2255b170-b345-4618-8c5e-d9dee0f1bb0d.jpg', '{https://cdn.toycker.in/products/e0cb83e4-e719-48f2-a3f2-6e1944b816b6.jpeg,https://cdn.toycker.in/products/d2b6416b-c472-4892-9097-4bdf34001fa2.jpeg,https://cdn.toycker.in/products/8ecb2752-6ee2-414d-ba8b-ff7133c85f92.jpeg}', 'inr', NULL, '', '', '[-0.003585541,-0.010927436,0.033279605,-0.008541976,0.0014200188,-0.028788447,-0.004356125,0.050217815,0.02004166,0.04468632,-0.04171445,0.0003513797,-0.05615113,-0.05884656,-0.015353558,0.011306155,-0.069113195,-0.02084425,-0.037017155,-0.07768454,-0.021157876,0.0008281429,0.02764099,0.050513618,0.0018612179,0.032763395,0.036861558,0.023516616,0.0051905084,-0.00360012,-0.0020166081,-0.011058745,0.005379079,-0.017692221,-0.07895086,-0.013345644,-0.038034413,0.019616034