	('prod_383d47fe-6b21-442f-8e27-b07d7d2cadc1', '6-wheel-off-road-monster-truck', '6-Wheel Off-Road Monster Truck', '<p>Unleash unstoppable fun with this durable, all-terrain toy truck.&nbsp;Just a gentle push is all it takes to send this inertia-powered fire truck rolling over any obstacle.&nbsp;Its six large, anti-skid rubber tires and shock-resistant suspension system are designed to handle grass, sand, mud, and more.&nbsp;Perfect for igniting imaginative play, this mini monster truck is an ideal gift for children aged 3 and up.</p>', 350, 'https://cdn.toycker.in/uploads/6-wheel-off-road-monster-truck/bf96133b-d3be-48d8-a182-d2d92cd9713d.png', 20, '{"compare_at_price": 499}', '2025-12-28 10:59:04.462851+00', '2025-12-28 10:59:04.462851+00', NULL, 'col_aa4de5eb-e030-4296-a866-7520c2b1a3e6', 'active', 'https://cdn.toycker.in/uploads/6-wheel-off-road-monster-truck/bf96133b-d3be-48d8-a182-d2d92cd9713d.png', '{https://cdn.toycker.in/uploads/6-wheel-off-road-monster-truck/bf96133b-d3be-48d8-a182-d2d92cd9713d.png,https://cdn.toycker.in/uploads/6-wheel-off-road-monster-truck/5a5e0785-bf98-46cb-be1d-c0818c055a8d.png,https://cdn.toycker.in/uploads/6-wheel-off-road-monster-truck/c1d28725-8c7a-41c2-a122-f338c25a6a66.webp,https://cdn.toycker.in/uploads/6-wheel-off-road-monster-truck/966a273a-c13f-41cc-83f3-197bd021dcde.jpg,https://cdn.toycker.in/uploads/6-wheel-off-road-monster-truck/f13240aa-eb52-4012-b5e4-ff00b0479030.jpg,https://cdn.toycker.in/uploads/6-wheel-off-road-monster-truck/30320d9d-e6be-42f9-ae53-800b592310ae.jpg,https://cdn.toycker.in/uploads/6-wheel-off-road-monster-truck/803a44e2-315c-4bfa-a49b-58e814dd02c8.webp}', 'inr', NULL, '', '', '[0.042730503,-0.012874562,0.017438252,-0.039026152,0.011503104,-0.007905265,0.04719147,0.02881605,0.07044733,-0.016078206,0.022701716,0.0030385612,-0.011296041,0.022304568,0.06479889,0.011490087,0.017898872,0.03808047,-0.01649615,-0.009918612,-0.03251104,0.0076243146,0.044286326,0.040818676,-0.014137737,0.022923693,0.020530686,-0