	('prod_f9b7e96b-c766-4024-bbbe-ee94b41517de', 'baby-spinner-3-pcs', 'Baby Spinner 3 PCS', '<ul><li><p>SENSORY DESIGN: Colourful butterfly-shaped spinner toys with adorable animal characters and tactile features to engage baby’s senses</p></li><li><p>INTERACTIVE PLAY: Each spinner features smooth-rotating centre pieces and musical notes design to stimulate visual and auditory development</p></li><li><p>SAFE MATERIALS: Constructed with durable, child-safe materials suitable for infants, featuring rounded edges and secure components</p></li><li><p>EASY TO HOLD: Perfect size for tiny hands with textured wings that help develop fine motor skills and hand-eye coordination</p></li><li><p>VERSATILE USE: Ideal for bath time entertainment, tummy time activities, or on-the-go play to keep babies engaged and entertained</p></li></ul>', 169, 'https://cdn.toycker.in/uploads/baby-spinner-3-pcs/23a725d3-8dcd-4389-abae-520cf3b667c5.jpg', 20, '{"compare_at_price": 199}', '2025-12-28 10:59:04.981702+00', '2025-12-28 10:59:04.981702+00', NULL, 'col_998e53b7-8f93-45de-bfd6-61e14e849b09', 'active', 'https://cdn.toycker.in/uploads/baby-spinner-3-pcs/23a725d3-8dcd-4389-abae-520cf3b667c5.jpg', '{https://cdn.toycker.in/uploads/baby-spinner-3-pcs/23a725d3-8dcd-4389-abae-520cf3b667c5.jpg,https://cdn.toycker.in/uploads/baby-spinner-3-pcs/a468ef9d-82b9-4bc0-8452-d5d874b4195a.jpg,https://cdn.toycker.in/uploads/baby-spinner-3-pcs/b7263e82-fde0-49aa-a47e-991226264eae.jpg,https://cdn.toycker.in/uploads/baby-spinner-3-pcs/910ea5f3-afdd-4cfe-b421-1f2f15d39dd8.jpg,https://cdn.toycker.in/uploads/baby-spinner-3-pcs/86126953-d192-407c-9d8f-f39a22a141bb.jpg,https://cdn.toycker.in/uploads/baby-spinner-3-pcs/0d989845-9b7b-425c-b3a3-02283bc4ee97.jpg}', 'inr', NULL, '', '', '[-0.002160298,-0.02672755,0.030253641,-0.006661669,-0.02818484,0.0140787875,0.045309026,0.018921342,0.015069196,0.00756905,0.031629477,0.011344622,-0.04744941,-0.0077389036,0.0011397939,-0.0073397015,-0.01525645,0.038044266,-0.03126517,-0