	('prod_cbae5241-9f7a-4a98-8c65-db43e9f06a3c', 'f003-car-rider', 'F003 Car Rider', '<ul><li><p>DESIGN FEATURES: Stylish red motorsport-themed ride-on car with realistic headlights, front grille, and sporty decals for an authentic look</p></li><li><p>SAFETY FIRST: Equipped with a comfortable backrest support, sturdy steering wheel, and stable four-wheel design for secure riding</p></li><li><p>EASY MOBILITY: Large, durable wheels and lightweight construction make it perfect for indoor and outdoor use on flat surfaces</p></li><li><p>COMFORT: Ergonomically designed seat with ample space and smooth edges ensures comfortable riding experience for little ones</p></li><li><p>AGE APPROPRIATE: Ideal push car for toddlers who are learning to scoot and navigate, helping develop motor skills and balance</p></li></ul>', 949, 'https://cdn.toycker.in/products/20b6e46a-0f49-4ccb-a7f2-738ac0be7c43.jpeg', 50, '{"compare_at_price": 1499}', '2025-12-28 10:59:11.026046+00', '2025-12-28 10:59:11.026046+00', 'cat_9bc270ab-aae0-44f2-a650-0ca133c39250', 'col_d27f16c3-8935-41d9-90af-5895ffef1e0c', 'active', 'https://cdn.toycker.in/uploads/f003-car-rider/5fdcec6e-bef7-4165-b5ff-2786082a5d43.jpg', '{https://cdn.toycker.in/products/20b6e46a-0f49-4ccb-a7f2-738ac0be7c43.jpeg,https://cdn.toycker.in/products/11072337-fbc7-4374-a7d4-aeffb826fb91.jpeg,https://cdn.toycker.in/products/197730c3-f725-42fd-ba7f-9329a89cefad.jpeg,https://cdn.toycker.in/products/75fde616-de81-4196-a78c-00e586f44217.jpeg,https://cdn.toycker.in/products/fb166979-94c9-4c0e-903c-c81fa1953d3b.jpeg}', 'inr', NULL, '', '', '[0.044914566,0.00676729,0.023197781,0.008921888,0.071983054,-0.0077812336,0.07422867,0.04358586,-0.0016589473,0.011399718,0.018451622,0.007951919,-0.008797726,-0.029757744,0.07003356,0.004891322,0.06314362,0.042075966,-0.014985847,-0.019486785,0.040305432,0.017478699,0.0327142,0.06996884,-0.010682476,0.011854484,0.024784325,-0.013216589,-0.014033328,-0.030072115,0.007863821,-0.02312901,0.014170678,0.045838516,-0