	('prod_111762cb-fa49-4708-826f-6a9440c09254', 'dancing-octopus-toy', 'DANCING OCTOPUS TOY', '<p>Wind Up Anmial Toy, Place It In Water And Watch Octopus Swim.<br>Lightweight And Easy For Little Hands To Operate.<br>Great For Bathtime Bath Or Pool Fun.<br>Really Swims In Water And Crawls On Land. Encourages Imaginative Play, No Batteries Required.<br>Made With Safe Elite Standard Non-Toxic PP And Odor-Free.<br></p>', 699, 'https://cdn.toycker.in/products/d7fd5afc-2ade-471e-8554-da30183f89d7.jpeg', 20, '{"compare_at_price": 899}', '2025-12-28 10:59:08.905168+00', '2025-12-28 10:59:08.905168+00', 'cat_94b4dcf4-745a-4430-a23c-e10f79594fa6', 'col_2c27fef3-dfee-42ef-8d1f-d08d41a2aad7', 'active', 'https://cdn.toycker.in/uploads/dancing-octopus-toy/1ae9ecc9-3b68-4ce3-8c06-e2bf9366051c.jpg', '{https://cdn.toycker.in/products/d7fd5afc-2ade-471e-8554-da30183f89d7.jpeg,https://cdn.toycker.in/products/fc5a392e-3170-4a8c-a7a0-815d6051194b.jpeg,https://cdn.toycker.in/products/f774284b-93e4-4906-ac33-cf275b7bbe67.jpeg,https://cdn.toycker.in/products/8fd214cb-7ea4-4175-8783-5b9f1a659e00.png,https://cdn.toycker.in/products/a784244a-0477-4474-8429-da89185fea3d.jpeg,https://cdn.toycker.in/products/287d3338-12bc-4d80-bd29-1f59eaa4ac11.jpeg,https://cdn.toycker.in/products/b9613858-3c9c-4a97-a51b-5d9bbed3809a.jpeg}', 'inr', NULL, '', '', '[0.00986598,-0.022432607,0.008668224,-0.020921418,-0.0014035058,-0.026462575,0.05681307,0.01777395,-0.042735115,0.008620055,0.023923624,-0.008080806,-0.008144473,0.0020906087,0.031007214,0.008973753,-0.11187052,0.029158562,0.022005955,0.0009846214,-0.08845182,0.016464438,0.016837338,0.034673437,-0.013277091,-0.0026667172,-0.036587596,-0.027139466,0.012658282,0.036535088,0.009363711,-0.033765487,-0.0037000806,-0.011852572,-0.10594046,0.013491571,-0.010166971,0.03206823,0.05768856,-0.0047260113,-0.034805115,-0.005299943,0.009768361,0.024324656,0.0056595863,-0.0110072065,0.05061329,-0.049831416,0.021538857,0.06807339,-0.010064652,0.02943098,-0.0030933626,-0