	('prod_f3af315d-445b-466e-87ec-b5bece68a122', 'mini-animal-pull-back', 'MINI ANIMAL PULL BACK', '<p>Zoom into fun with the Animal Rollers: Pull-Back Buddies!&nbsp;This delightful set of four friction-powered toy cars features a charming cast of characters, including a cool blue whale, a fierce red bulldog, a playful green dinosaur, and a fluffy white lion.&nbsp;Simply pull them back and watch them race across the floor, bringing endless entertainment to playtime.&nbsp;Made from durable, child-safe plastic, these toys are perfect for little hands to grip and play with.&nbsp;They encourage imaginative play and help develop fine motor skills.&nbsp;A perfect gift for toddlers and young children who love animals and vehicles.</p>', 99, 'https://cdn.toycker.in/uploads/mini-animal-pull-back/059b6437-475f-4148-84ae-e6a7b8ff6d96.jpg', 20, '{"compare_at_price": 199}', '2025-12-28 10:59:15.824675+00', '2025-12-28 10:59:15.824675+00', 'cat_a31a4862-ab6c-4dd6-a5d0-985b94eedbbf', 'col_4d51f80f-e115-49f5-9990-8277b8b5a8b3', 'active', 'https://cdn.toycker.in/uploads/mini-animal-pull-back/86cd4f3a-96bb-4528-8183-a0b1ada57e45.jpg', '{https://cdn.toycker.in/uploads/mini-animal-pull-back/059b6437-475f-4148-84ae-e6a7b8ff6d96.jpg,https://cdn.toycker.in/uploads/mini-animal-pull-back/3fa67fb2-629d-413d-a678-238334dca136.jpg,https://cdn.toycker.in/uploads/mini-animal-pull-back/7ee5c05f-f245-4e62-9910-3a91e5cc9db1.png,https://cdn.toycker.in/uploads/mini-animal-pull-back/a28b07d4-e920-4327-aaf5-99b42e48df6b.png}', 'inr', NULL, '', '', '[0.015100441,0.0037571802,0.031416737,0.018115666,-0.0037763414,0.034573726,0.05166217,0.011220499,0.012138854,0.04757361,-0.0092088105,-0.015084969,-0.048775263,0.019892642,0.089642726,0.024089908,-0.09558125,-0.025232242,0.0033949022,-0.010101661,-0.073755935,-0.04180879,0.004180329,-0.016743066,-0.05299655,0.0016651924,-0.044327952,-0.007473289,-0.016808972,-0.0016499965,0.02171573,-0.021869387,0.0012250363,-0.021980766,-0.03955701,0.029081963,-0.005741137,