	('prod_954ec2ac-f983-4f01-bf70-b8764e514764', 'super-shot-blaster-gun', 'Super Shot Blaster Gun', '<ul><li><p>The Blaster Soft Bullet is a toy gun designed for kids, featuring foam bullet darts for safe and enjoyable play. Children can engage in exciting shooting games and hit imaginary targets with soft foam bullets.</p></li><li><p>Shoot with precision and keep your ammo at your fingertips – with our Hand Strap for Soft Dart Bullet ! Quickly and easily store up to 10 soft bullets on your hand so you can reload faster than ever.</p></li><li><p>Rapid-Fire Action: The Hot Fire Gun is easy to operate, allowing kids to load up to 4 darts at once. The pump action handle enables quick preparation for rapid-fire action, adding to the excitement and intensity of play.</p></li></ul>', 349, 'https://cdn.toycker.in/products/85bc284d-fa4f-40ed-8ddc-87be90397450.jpeg', 19, '{"compare_at_price": 450}', '2025-12-28 10:59:21.766499+00', '2025-12-28 10:59:21.766499+00', 'cat_aef0da25-a920-495d-af0a-9ce132e7c89c', 'col_37cccc82-dee7-4ce4-9d1f-cf6b20863ad0', 'active', 'https://cdn.toycker.in/uploads/super-shot-blaster-gun/85011ce9-21f0-46fc-bcda-562d4ddfb3b5.webp', '{https://cdn.toycker.in/products/85bc284d-fa4f-40ed-8ddc-87be90397450.jpeg,https://cdn.toycker.in/products/d6382953-68cb-4f81-ad9d-43a7fb448667.jpeg,https://cdn.toycker.in/products/3940b744-3cf0-43b9-8331-f16536e672c8.jpeg,https://cdn.toycker.in/products/857e1620-5ffc-41fc-9cfa-bba064d621d5.jpeg}', 'inr', NULL, '', '', '[0.034214534,-0.0016310657,0.014190378,-0.030625824,0.04086521,0.025923172,0.01704263,0.055686053,-0.013140278,-0.0015219079,-0.028553482,-0.00041636612,-0.020760404,-0.024707623,0.037663825,-0.010340021,0.0091269165,0.04662758,-0.012782319,-0.02526859,-0.027946018,0.01388011,-0.0036139574,0.06360885,0.0019885015,0.029114155,0.036801856,0.010418531,-0.003364299,-0.024307663,0.0021476033,-0.0018466075,0.014701042,0.01604222,-0.063453995,-0.038114984,-0.03076699,0.016257655,0.045225553,-0.0070370934,-0.01480