	('prod_53278d58-3871-480f-993b-c199ac001149', 'colour-coder-game', 'Colour Coder Game', '<ul><li><p>Colorful Disc Matching Game – Sort and match the red, green, blue, and orange discs into their correct positions.</p></li><li><p>Encourages Thinking Skills – Children must plan and decide how to move discs to the right places.</p></li><li><p>Boosts Fine Motor Skills – Moving the discs helps strengthen hand muscles and improve control. Supports Hand-Eye Coordination – Kids practice aiming and guiding the pieces into place</p></li></ul>', 299, 'https://cdn.toycker.in/products/0879b50c-ef44-48c4-aedb-7f3f8b3f9178.jpeg', 20, '{"compare_at_price": 359}', '2025-12-28 10:59:08.123424+00', '2025-12-28 10:59:08.123424+00', 'cat_faea0711-a3b3-422e-a496-772919c14df6', 'col_151b58e4-30fe-431c-8a44-bd622c4c1c6e', 'active', 'https://cdn.toycker.in/uploads/colour-coder-game/99850e54-6acc-4119-8b1a-ba563bb299a1.webp', '{https://cdn.toycker.in/products/0879b50c-ef44-48c4-aedb-7f3f8b3f9178.jpeg,https://cdn.toycker.in/products/57af6812-3163-418d-88d6-5023c0e37a40.jpeg,https://cdn.toycker.in/products/913aeeb6-038f-4e84-8d9b-ce205bf22b08.jpeg,https://cdn.toycker.in/products/fe534b34-0ebe-4417-9247-b182058d8a61.jpeg}', 'inr', NULL, '', '', '[0.025512464,-0.018124394,0.03214357,0.06886613,0.010228252,-0.027226679,0.02560958,-0.0017581785,-0.04591932,0.0025523137,-0.0554665,0.0036265277,0.008212198,0.0077868626,0.014167858,-0.0022567636,-0.012281598,0.012773289,-0.04488612,-0.06453233,0.0031165106,-0.041697014,0.028344993,0.023318168,0.01052596,0.003880908,-0.03866427,-0.006737173,0.053563412,-0.007522115,-0.0036267478,0.0046006455,-0.0045146095,0.038133178,-0.02147862,-0.027498294,-0.04578785,0.037129134,0.012227348,-0.10580801,-0.03296589,0.0011237664,0.0014242812,0.0024873978,-0.04211448,-0.017919946,0.02446212,-0.07851968,-0.023051271,0.05892817,0.052356295,0.007920455,0.012022314,0.015722025,-0.04773073,-0.02118914,-0.013317763,-0.007590494,0.018713178,-0.016745497,0.0006587313,-0.0262