	('prod_d5d2c680-827c-4453-b794-465b6fe304e7', 'h6-hoverboard-1', 'H6+ HOVERBOARD', '<p><br>FREE ACCESSORIES – Free Carry Bag, Handle Attachment, Charger, Protection Kit and Remote with the Product.</p><p>START-UP BALANCE 2.0 – Assists in Balancing the Hoverboard with the 5th GEN Control Board</p><p>BLUETOOTH ENABLED – Play Music while riding with a built-in speaker</p><p>LED FLASH WHEEL – Attractive-looking LED Wheel Hub Motor with Cool LEDs.</p><p>PLUS SPECIAL – Bigger Battery (20% More than H6 Classic) and Lifting Handle and More Motor Power with More Load Taking Capability.</p><p>POWERFUL PERFORMANCE – Race up to 15km/h and climb inclines up to 20 Degrees</p><p>FOR ALL RIDERS – Perfect for all Ages 7+ and up to 90kg Load</p>', 12999, 'https://cdn.toycker.in/products/8c5e4034-51fb-421f-b6df-847b363a36c7.jpeg', 20, '{"compare_at_price": 15998.99}', '2025-12-28 10:59:14.337052+00', '2025-12-28 10:59:14.337052+00', NULL, 'col_d27f5db1-f6f6-4565-b0da-885ae6a4e45c', 'active', 'https://cdn.toycker.in/uploads/h6-hoverboard-1/84ba4b50-ea4a-4ae6-aaef-d8227b366aca.webp', '{https://cdn.toycker.in/products/8c5e4034-51fb-421f-b6df-847b363a36c7.jpeg,https://cdn.toycker.in/products/58c4b5e8-3071-42e1-b167-d47ac145dbdd.jpeg,https://cdn.toycker.in/products/7213d0c3-590a-4f23-a83f-1c83ea2e7c6d.jpeg,https://cdn.toycker.in/products/f370335e-1015-420e-bb3f-5d7d7f4d115c.jpeg,https://cdn.toycker.in/products/2d19551b-ff3d-45c4-a450-a87d6bd1c17c.jpeg,https://cdn.toycker.in/products/831b8a95-951f-4cd2-9244-47f6f6ecae52.jpeg}', 'inr', NULL, '', '', '[0.003840745,0.0015985796,0.002979625,0.0031845262,0.05411337,0.003949973,0.0363024,0.04016617,-0.005837889,0.024765324,0.0014206899,0.028107736,-0.008779411,-0.06279574,0.016682904,0.020074526,0.024624895,0.03063815,-0.009613408,-0.048539598,0.023338826,-0.02234274,0.007983506,0.027955724,0.0017124756,-0.00070380024,0.0692873,-0.006434777,-0.019969676,0.013567056,0.0026940915,0.028417582,-0.03400377,-0.02681911,-0.067954004,-0.011786283,-0.025