	('prod_ac509288-f624-4d8a-9152-7691830b4123', 'beauty-set-mini', 'Beauty Set Mini', '<p>Roleplay set is completely pretended, but it looks and feels real! No mess and no coloring, just pretend play fun! Made of eco-friendly material, safe and non-toxic, beautifully shaped, rounded and burr-free.<br>This is a compact pretend play set for kids, all the items come packed in a neat carrying case foe easy storage and it’s not easy to lose and avoid breaking during carrying.<br>Barbie Pretend play kit will help little kids to explore their imagination and creativity. It would be a fantastic present for them.</p>', 149.01, 'https://cdn.toycker.in/uploads/beauty-set-mini/06808783-dfde-4da7-97f6-e20d8535194c.webp', 20, '{"compare_at_price": 199}', '2025-12-28 10:59:05.511242+00', '2025-12-28 10:59:05.511242+00', NULL, 'col_1ed8436d-f24e-4723-8ad3-e50ca8ea9e71', 'active', 'https://cdn.toycker.in/uploads/beauty-set-mini/06808783-dfde-4da7-97f6-e20d8535194c.webp', '{https://cdn.toycker.in/uploads/beauty-set-mini/06808783-dfde-4da7-97f6-e20d8535194c.webp,https://cdn.toycker.in/uploads/beauty-set-mini/2d9a9bd6-5980-4e16-8fb9-aa4669ff1041.webp,https://cdn.toycker.in/uploads/beauty-set-mini/ffd3c4fa-8e13-438c-b1f4-5ca6de92aa49.jpg,https://cdn.toycker.in/uploads/beauty-set-mini/a6689fb9-fd6a-4aa1-b739-2f2eae9414df.webp}', 'inr', NULL, '', '', '[-0.72560817,-0.2337922,0.3321673,0.38216737,0.45666885,-0.061156046,-0.3299351,0.019157227,0.4510337,0.1933912,0.37312794,-0.01255778,0.120868616,0.11465208,0.065061726,-0.053827662,-0.31145668,0.22877967,-0.2609558,-0.48024857,-0.85169184,-0.42556047,-0.014947298,-0.21944048,0.033340465,0.45061928,-0.24137348,0.11666242,-0.23136377,0.029401971,0.36248696,0.14493906,0.071591005,-0.28092733,-0.22251663,-0.6064181,0.10321098,-0.16876753,-0.17043032,-0.025746379,0.29412884,0.31505406,0.08055846,0.3320115,0.115773946,0.39734858,0.27675653,-0.5304863,-0.49441814,-0.027093396,0.08971786,-0.18244606,0.1837403,0.0808646,0.06435171,-0.13845903,-0.121