	('prod_5b6acec2-7014-453e-a503-324e40cf901e', 'toyshine-pvc-speed-up-led-light-up-glow-football-night-sport-game-training-indooroutdoor-soccer-ball', 'Toyshine PVC Speed Up LED Light Up Glow Football Night Sport Game Training Indoor/Outdoor Soccer Ball', '<ul><li><p>Glow-in-the-Dark LED Light-Up Football – Features built-in bright LED lights that automatically illuminate upon impact, making it perfect for nighttime sports, training, and fun play.</p></li><li><p></p></li><li><p>making it suitable for kids, teenagers, and adults, ensuring an authentic soccer experience.</p></li><li><p></p></li><li><p>Durable &amp; High-Quality Material – Crafted from Quality PVC synthetic leather and reinforced rubber bladder, ensuring long-lasting durability, superior grip, and optimal air retention.</p></li><li><p></p></li><li><p>Indoor &amp; Outdoor Play – Whether it''s a backyard game, park match, beach kickabout, or indoor practice, this LED football is designed for all types of playing surfaces.</p></li><li><p></p></li><li><p>Toyshine Fun-Sports Series - Toyshine Presents a new way of Fun and entertainment for kids. In Fun-Sports series we provide products which provides learning as well as sports activity for kids</p></li></ul><p></p>', 1299, 'https://cdn.toycker.in/products/27c67779-8f97-4de0-941a-8f232330f557.jpeg', 50, '{"compare_at_price": 1999}', '2026-03-27 11:55:25.914313+00', '2026-03-27 11:55:25.914313+00', 'cat_94b4dcf4-745a-4430-a23c-e10f79594fa6', 'col_5952bc0e-92a8-4ba5-8232-045f9bb7faa7', 'active', NULL, '{https://cdn.toycker.in/products/27c67779-8f97-4de0-941a-8f232330f557.jpeg,https://cdn.toycker.in/products/e2bd7497-9935-403d-8395-554456d31950.jpeg,https://cdn.toycker.in/products/a0602f7e-0e26-4e39-9a80-b582a66f965d.jpeg,https://cdn.toycker.in/products/d401848d-77e0-48a3-b59e-7eeadcbd0cca.jpeg,https://cdn.toycker.in/products/0e246519-f4d9-48f1-a62e-23da632d8732.jpeg,https://cdn.toycker.in/products/088d3bfa-db02-4332-a963-b0dd9665e2bb.jpeg}', 'inr', NULL, 'Glow